Method Code:
    public byte[] xor(byte[] arr1, byte[] arr2) {
        byte[] res = new byte[arr1.length];
        int i = 0;
        byte[] byArray = arr1;
        int n = arr1.length;
        int n2 = 0;
        while (n2 < n) {
            byte b = byArray[n2];
            res[i] = (byte)(b ^ arr2[i++]);
            ++n2;
        }
        return res;
    }

